import React, { useState, useCallback } from 'react';
import { useDropzone } from 'react-dropzone';
import { uploadFile, deletePath } from '../services/api';
import { 
  Button, 
  Dialog, 
  DialogTitle, 
  DialogContent, 
  DialogActions, 
  Stack,
  LinearProgress,
  Typography,
  Box,
  Alert,
  IconButton,
  Paper,
  List,
  ListItem,
  ListItemText,
  ListItemIcon,
  Collapse,
  Checkbox
} from '@mui/material';
import CloudUploadIcon from '@mui/icons-material/CloudUpload';
import FolderIcon from '@mui/icons-material/Folder';
import InsertDriveFileIcon from '@mui/icons-material/InsertDriveFile';
import DeleteIcon from '@mui/icons-material/Delete';
import ExpandMoreIcon from '@mui/icons-material/ExpandMore';
import ExpandLessIcon from '@mui/icons-material/ExpandLess';
import CloseIcon from '@mui/icons-material/Close';

const FileTreeItem = ({ item, level = 0, selected, onSelect, onToggle, expanded }) => {
  const isFolder = item.type === 'folder';

  return (
    <>
      <ListItem 
        sx={{ 
          pl: level * 2 + 2,
          bgcolor: selected ? 'action.selected' : 'transparent'
        }}
        secondaryAction={
          <Checkbox
            edge="end"
            checked={selected}
            onChange={(e) => onSelect(item.path, e.target.checked)}
          />
        }
      >
        <ListItemIcon>
          {isFolder ? (
            <IconButton size="small" onClick={() => onToggle(item.path)}>
              {expanded ? <ExpandLessIcon /> : <ExpandMoreIcon />}
            </IconButton>
          ) : (
            <InsertDriveFileIcon />
          )}
        </ListItemIcon>
        <ListItemText 
          primary={item.name}
          secondary={isFolder ? `${item.files?.length || 0} items` : null}
        />
      </ListItem>
      {isFolder && expanded && item.files && (
        <Collapse in={expanded}>
          <List disablePadding>
            {item.files.map((child, index) => (
              <FileTreeItem
                key={child.path || index}
                item={child}
                level={level + 1}
                selected={selected}
                onSelect={onSelect}
                onToggle={onToggle}
                expanded={expanded}
              />
            ))}
          </List>
        </Collapse>
      )}
    </>
  );
};

const UploadPanel = ({ onUploadSuccess = () => {} }) => {
  const [uploading, setUploading] = useState(false);
  const [uploadStatus, setUploadStatus] = useState(null);
  const [progress, setProgress] = useState(0);
  const [error, setError] = useState(null);

  const processFiles = async (files) => {
    let processed = 0;
    const results = {
      successful: [],
      failed: [],
      skipped: []
    };

    try {
      // Convert FileList to Array and sort by path to maintain folder structure
      const fileArray = Array.from(files).sort((a, b) => {
        const pathA = (a.webkitRelativePath || a.path || a.name).toLowerCase();
        const pathB = (b.webkitRelativePath || b.path || b.name).toLowerCase();
        return pathA.localeCompare(pathB);
      });

      // Process each file
      for (const file of fileArray) {
        try {
          // Get the relative path from the file
          const relativePath = file.webkitRelativePath || file.path || '';
          let uploadPath = '';

          if (relativePath) {
            // For folder upload, use the path without the first directory and filename
            const parts = relativePath.split('/');
            if (parts.length > 1) {
              // Remove the first directory (root folder name) and the filename
              uploadPath = parts.slice(1, -1).join('/');
            }
          }

          console.log(`Processing file: ${file.name} in path: ${uploadPath}`);
          const result = await uploadFile(file, uploadPath);

          results.successful.push({ 
            file: uploadPath ? `${uploadPath}/${file.name}` : file.name,
            result 
          });
        } catch (error) {
          console.error(`Failed to upload ${file.name}:`, error);
          results.failed.push({ 
            file: file.webkitRelativePath || file.path || file.name,
            error: error.message || 'Unknown error occurred'
          });
        }

        processed++;
        setProgress((processed / fileArray.length) * 100);
      }
    } catch (error) {
      console.error('Error processing files:', error);
      results.failed.push({
        file: 'batch upload',
        error: error.message || 'Unknown error occurred'
      });
    }

    return results;
  };

  const onDrop = useCallback(async (acceptedFiles) => {
    if (acceptedFiles.length === 0) return;

    setUploading(true);
    setUploadStatus(null);
    setProgress(0);
    setError(null);

    try {
      console.log(`Starting upload of ${acceptedFiles.length} files`);
      const results = await processFiles(acceptedFiles);

      console.log('Final upload results:', results);
      setUploadStatus({
        successful: results.successful.length,
        failed: results.failed.map(f => `${f.file}: ${f.error}`),
        skipped: results.skipped.map(f => `${f.file}: ${f.reason}`),
        details: results
      });

      if (results.successful.length > 0) {
        onUploadSuccess();
      }
    } catch (error) {
      console.error('Upload error:', error);
      setError(error.message || 'Unknown error occurred');
    } finally {
      setUploading(false);
    }
  }, [onUploadSuccess]);

  const handleFileSelect = (isFolder = false) => {
    const input = document.createElement('input');
    input.type = 'file';
    input.multiple = true;

    if (isFolder) {
      input.webkitdirectory = true;
      input.directory = true;
    }

    input.onchange = (e) => {
      const files = Array.from(e.target.files);
      if (files.length > 0) {
        onDrop(files);
      }
    };

    input.click();
  };

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    noClick: true,
    noKeyboard: uploading,
    noDrag: uploading
  });

  return (
    <div className="upload-panel">
      <Box sx={{ p: 3 }}>
        <Stack spacing={2} direction="column" alignItems="center">
          {error && (
            <Alert 
              severity="error" 
              onClose={() => setError(null)}
              sx={{ width: '100%', mb: 2 }}
            >
              {error}
            </Alert>
          )}

          {/* Dropzone */}
          <Paper
            {...getRootProps()}
            sx={{
              width: '100%',
              p: 3,
              textAlign: 'center',
              cursor: uploading ? 'not-allowed' : 'pointer',
              bgcolor: isDragActive ? 'action.hover' : 'background.paper',
              border: '2px dashed',
              borderColor: isDragActive ? 'primary.main' : 'divider',
              '&:hover': {
                bgcolor: 'action.hover',
              },
            }}
          >
            <input {...getInputProps()} />
            <CloudUploadIcon sx={{ fontSize: 48, color: 'primary.main', mb: 2 }} />
            <Typography variant="h6" gutterBottom>
              {uploading ? 'Uploading...' : 'Drag & drop files or folders here'}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {isDragActive
                ? 'Drop the files or folders here...'
                : 'or use the buttons below'}
            </Typography>
          </Paper>

          {/* Upload Buttons */}
          <Stack direction="row" spacing={2} sx={{ width: '100%' }}>
            <Button
              variant="contained"
              startIcon={<CloudUploadIcon />}
              onClick={() => handleFileSelect(false)}
              disabled={uploading}
              fullWidth
            >
              Upload Files
            </Button>
            <Button
              variant="contained"
              startIcon={<FolderIcon />}
              onClick={() => handleFileSelect(true)}
              disabled={uploading}
              fullWidth
            >
              Upload Folder
            </Button>
          </Stack>

          {/* Upload Progress */}
          {uploading && (
            <Box sx={{ width: '100%', mt: 2 }}>
              <LinearProgress variant="determinate" value={progress} />
              <Typography variant="body2" color="text.secondary" align="center" sx={{ mt: 1 }}>
                {Math.round(progress)}%
              </Typography>
            </Box>
          )}
        </Stack>
      </Box>

      {/* Results Dialog */}
      {uploadStatus && (
        <Dialog 
          open={!!uploadStatus} 
          onClose={() => setUploadStatus(null)}
          maxWidth="sm"
          fullWidth
        >
          <DialogTitle>
            Upload Results
            <IconButton
              aria-label="close"
              onClick={() => setUploadStatus(null)}
              sx={{
                position: 'absolute',
                right: 8,
                top: 8,
              }}
            >
              <CloseIcon />
            </IconButton>
          </DialogTitle>
          <DialogContent>
            <Box sx={{ py: 2 }}>
              {/* Summary */}
              <Stack spacing={1}>
                {uploadStatus.successful > 0 && (
                  <Typography variant="subtitle1" color="success.main">
                    Successfully uploaded: {uploadStatus.successful} files
                  </Typography>
                )}
                {uploadStatus.failed.length > 0 && (
                  <Typography variant="subtitle1" color="error">
                    Failed: {uploadStatus.failed.length} files
                  </Typography>
                )}
                {uploadStatus.skipped?.length > 0 && (
                  <Typography variant="subtitle1" color="text.secondary">
                    Skipped: {uploadStatus.skipped.length} files
                  </Typography>
                )}
              </Stack>

              {/* Failed uploads */}
              {uploadStatus.failed.length > 0 && (
                <Box sx={{ mt: 3 }}>
                  <Typography variant="h6" color="error" gutterBottom>
                    Failed uploads:
                  </Typography>
                  <Box sx={{ 
                    maxHeight: '200px', 
                    overflowY: 'auto', 
                    border: '1px solid rgba(255, 0, 0, 0.2)',
                    borderRadius: 1,
                    p: 2,
                    bgcolor: 'rgba(255, 0, 0, 0.05)'
                  }}>
                    {uploadStatus.failed.map((error, index) => (
                      <Typography 
                        key={index} 
                        variant="body2" 
                        color="error" 
                        sx={{ 
                          mb: 1,
                          '&:last-child': { mb: 0 },
                          wordBreak: 'break-word'
                        }}
                      >
                        {error}
                      </Typography>
                    ))}
                  </Box>
                </Box>
              )}

              {/* Successful uploads */}
              {uploadStatus.details?.successful.length > 0 && (
                <Box sx={{ mt: 3 }}>
                  <Typography variant="h6" color="success.main" gutterBottom>
                    Successfully uploaded files:
                  </Typography>
                  <Box sx={{ 
                    maxHeight: '200px', 
                    overflowY: 'auto',
                    border: '1px solid rgba(0, 255, 0, 0.2)',
                    borderRadius: 1,
                    p: 2,
                    bgcolor: 'rgba(0, 255, 0, 0.05)'
                  }}>
                    {uploadStatus.details.successful.map((item, index) => (
                      <Typography 
                        key={index} 
                        variant="body2" 
                        color="success.main"
                        sx={{ 
                          mb: 1,
                          '&:last-child': { mb: 0 },
                          wordBreak: 'break-word'
                        }}
                      >
                        {item.file}
                      </Typography>
                    ))}
                  </Box>
                </Box>
              )}
            </Box>
          </DialogContent>
          <DialogActions>
            <Button onClick={() => setUploadStatus(null)}>Close</Button>
          </DialogActions>
        </Dialog>
      )}
    </div>
  );
};

export default UploadPanel;
